SELECT version 
FROM experiments 
WHERE researcher_id = 1;

SELECT AVG(reward) AS average_reward 
FROM experiment_results 
WHERE experiment_id = 1;

SELECT experiment_id, algorithm, environment, hyperparameters, start_time, end_time, status, researcher_id, notes, version, encryption_key, last_updated
FROM experiments
WHERE algorithm = 'PPO' AND environment = 'Atari';

SELECT experiments.experiment_id, experiments.algorithm, hyperparameters.name, hyperparameters.value
FROM experiments
LEFT JOIN hyperparameters ON experiments.experiment_id = hyperparameters.experiment_id;

SELECT e.experiment_id, e.algorithm, e.environment, e.hyperparameters, e.start_time, e.end_time, e.status, e.researcher_id, e.notes, e.version
FROM experiments e
WHERE e.experiment_id = (
    SELECT MAX(experiment_id)
    FROM experiments
);
